// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	// Add your code here
	// RAJ 2020.02.29 - STRY0059417
	// This put the short description into the document library.
	// 2020.03.09 changed to put the taskernumber - S into the document library
	//current.u_shared_task_label = current.u_task_ref.getDisplayValue() + '-S';
	//current.u_shared_task_label = current.u_task_ref.taskernumber + '-S';

	//  STRY0051139 Set the Tree Level Tasker Number and use it in all other Tasks
	// ships with the defalut setting YY-000001;
	var taskerNM = new TaskerDisplayValueConfiguration();
	var taskTreeNumber = taskerNM.setTaskTreeNumber(current);
	current.number = taskTreeNumber;
	current.u_shared_task_label = taskTreeNumber;

})(current, previous);
